<?php declare(strict_types=1);require __DIR__.'/../includes/functions.php';require __DIR__.'/autoload.php';use App\Models\User;$message='';$error='';if($_SERVER['REQUEST_METHOD']==='POST'){$name=trim((string)($_POST['name']??''));if($name==='')$error='Vui lòng nhập tên người dùng.';else{$user=new User($name);$message=$user->sayHello();}}$pageTitle='Bài 05 - Namespace';$basePath='..';$current='bai05';require __DIR__.'/../includes/header.php';?>
<div class="crumb"><a href="../index.php">Trang chủ</a> / Bài 05</div><h1>Namespace và Autoloading</h1><p class="subtitle">Class User thuộc App\Models và được nạp qua spl_autoload_register().</p><div class="two"><section class="card"><h2>Tạo User</h2><?php if($error):?><div class="alert err"><?=e($error)?></div><?php endif;?><form method="post"><div class="group"><label>Tên người dùng</label><input name="name" value="<?=old('name','Nguyễn Hữu Thắng')?>" required></div><div class="actions"><button class="btn primary">Gọi sayHello()</button></div></form><div class="note">index.php không require trực tiếp User.php. Autoloader ánh xạ namespace sang đường dẫn file.</div></section><aside class="card"><div class="result"><h2>Kết quả</h2><?php if($message):?><div class="item"><strong><?=e($message)?></strong></div><?php else:?><p class="muted">Chưa khởi tạo User.</p><?php endif;?></div></aside></div><?php require __DIR__.'/../includes/footer.php';?>
